using System;
using System.Threading;
using System.Threading.Tasks;

/// <summary>
/// .NET 8 migration of BackgroundProcessor.
/// Uses CancellationToken instead of Thread.Abort (removed in .NET 6+).
/// </summary>
public class BackgroundProcessor : IDisposable
{
    private Task? _workerTask;
    private CancellationTokenSource? _cts;

    public void Start()
    {
        _cts = new CancellationTokenSource();
        var token = _cts.Token;

        // Task.Run uses the thread pool; no manual Thread management needed
        _workerTask = Task.Run(() => ProcessLoop(token), token);
    }

    private void ProcessLoop(CancellationToken token)
    {
        while (!token.IsCancellationRequested)
        {
            try
            {
                // Pass the token so blocking calls can be interrupted cooperatively
                var item = GetNextItem(token);
                ProcessItem(item);
            }
            catch (OperationCanceledException) when (token.IsCancellationRequested)
            {
                // Cancellation requested — roll back and exit cleanly
                RollbackCurrentTransaction();
                break;
            }
            finally
            {
                FlushBuffers();
            }
        }
    }

    public async Task StopAsync(TimeSpan? timeout = null)
    {
        if (_cts is null || _workerTask is null)
            return;

        // Signal cancellation (replaces _running = false + Thread.Abort)
        _cts.Cancel();

        // Wait with a timeout instead of Thread.Sleep + Abort
        var effectiveTimeout = timeout ?? TimeSpan.FromSeconds(5);
        if (await Task.WhenAny(_workerTask, Task.Delay(effectiveTimeout)) != _workerTask)
        {
            // Worker didn't finish in time — log a warning.
            // In .NET 8 there is NO way to forcibly kill a thread. You must
            // ensure all blocking calls accept and honor CancellationToken.
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _workerTask = null;
    }

    // --- Stubs for illustration ---
    private object GetNextItem(CancellationToken token)
    {
        // Example: a BlockingCollection or Channel that accepts a token
        // _queue.Take(token);  // throws OperationCanceledException on cancel
        token.ThrowIfCancellationRequested();
        return new object();
    }

    private void ProcessItem(object item) { }
    private void RollbackCurrentTransaction() { }
    private void FlushBuffers() { }
}

